import React, { useState, useRef, useCallback, useEffect } from 'react';
import './Canvas.css';
import { Sparkles, Package, Settings, Upload, Plus, Minus, Palette } from 'lucide-react';

const Canvas: React.FC = () => {
  const [zoom, setZoom] = useState(27);
  const [canvasPosition, setCanvasPosition] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const [isSpacePressed, setIsSpacePressed] = useState(false);
  const [canvasColor, setCanvasColor] = useState('#2B2B2B');
  const [showDots, setShowDots] = useState(true);
  const [showColorPicker, setShowColorPicker] = useState(false);
  const canvasRef = useRef<HTMLDivElement>(null);
  const dragStart = useRef({ x: 0, y: 0 });
  const colorPickerRef = useRef<HTMLDivElement>(null);

  const handleZoomIn = () => {
    setZoom(prev => Math.min(prev + 10, 200));
  };

  const handleZoomOut = () => {
    setZoom(prev => Math.max(prev - 10, 10));
  };

  const toggleColorPicker = () => {
    setShowColorPicker(prev => !prev);
  };

  const toggleDots = () => {
    setShowDots(prev => !prev);
  };

  const handleColorChange = (color: string) => {
    setCanvasColor(color);
  };

  const handleGradientClick = (e: React.MouseEvent<HTMLDivElement>) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;

    // Convert position to HSV and then to hex
    const hue = x * 360;
    const saturation = 1 - y;
    const value = 1;

    const hex = hsvToHex(hue, saturation, value);
    setCanvasColor(hex);
  };

  const handleHueClick = (e: React.MouseEvent<HTMLDivElement>) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const hue = x * 360;

    const hex = hsvToHex(hue, 1, 1);
    setCanvasColor(hex);
  };

  // Convert HSV to Hex
  const hsvToHex = (h: number, s: number, v: number): string => {
    const c = v * s;
    const x = c * (1 - Math.abs(((h / 60) % 2) - 1));
    const m = v - c;

    let r = 0, g = 0, b = 0;

    if (0 <= h && h < 60) {
      r = c; g = x; b = 0;
    } else if (60 <= h && h < 120) {
      r = x; g = c; b = 0;
    } else if (120 <= h && h < 180) {
      r = 0; g = c; b = x;
    } else if (180 <= h && h < 240) {
      r = 0; g = x; b = c;
    } else if (240 <= h && h < 300) {
      r = x; g = 0; b = c;
    } else if (300 <= h && h < 360) {
      r = c; g = 0; b = x;
    }

    r = Math.round((r + m) * 255);
    g = Math.round((g + m) * 255);
    b = Math.round((b + m) * 255);

    return `#${r.toString(16).padStart(2, '0')}${g.toString(16).padStart(2, '0')}${b.toString(16).padStart(2, '0')}`;
  };

  // Close color picker when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (colorPickerRef.current && !colorPickerRef.current.contains(event.target as Node)) {
        setShowColorPicker(false);
      }
    };

    if (showColorPicker) {
      document.addEventListener('mousedown', handleClickOutside);
      return () => {
        document.removeEventListener('mousedown', handleClickOutside);
      };
    }
  }, [showColorPicker]);

  // Handle space key for dragging
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.code === 'Space' && !isSpacePressed) {
        e.preventDefault();
        setIsSpacePressed(true);
      }
    };

    const handleKeyUp = (e: KeyboardEvent) => {
      if (e.code === 'Space') {
        e.preventDefault();
        setIsSpacePressed(false);
        setIsDragging(false);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, [isSpacePressed]);

  // Handle mouse events for dragging
  const handleMouseDown = useCallback((e: React.MouseEvent) => {
    if (isSpacePressed) {
      setIsDragging(true);
      dragStart.current = { x: e.clientX - canvasPosition.x, y: e.clientY - canvasPosition.y };
    }
  }, [isSpacePressed, canvasPosition]);

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
    if (isDragging && isSpacePressed) {
      setCanvasPosition({
        x: e.clientX - dragStart.current.x,
        y: e.clientY - dragStart.current.y
      });
    }
  }, [isDragging, isSpacePressed]);

  const handleMouseUp = useCallback(() => {
    setIsDragging(false);
  }, []);

  return (
    <div 
      className={`canvas ${isSpacePressed ? 'space-pressed' : ''}`}
      ref={canvasRef}
      onMouseDown={handleMouseDown}
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
      style={{ backgroundColor: canvasColor }}
    >
      <div 
        className="canvas-content"
        style={{
          transform: `translate(${canvasPosition.x}px, ${canvasPosition.y}px) scale(${zoom / 100})`,
          backgroundImage: showDots ? `
            radial-gradient(circle at 25% 25%, ${canvasColor === '#ffffff' ? '#000000' : '#ffffff'} 1px, transparent 1px),
            radial-gradient(circle at 75% 75%, ${canvasColor === '#ffffff' ? '#000000' : '#ffffff'} 1px, transparent 1px)
          ` : 'none',
          backgroundSize: '20px 20px',
          backgroundPosition: '0 0, 10px 10px'
        }}
      >
        <div className="placeholder-message">
          <Sparkles className="sparkle-icon" size={16} />
          <span>Double-click anywhere to create a new component or click the + button</span>
        </div>
      </div>

      {/* Top Left Controls */}
      <div className="control-group top-left">
        <div className="components-dropdown">
          <Package size={16} />
          <span>Components</span>
          <span className="dropdown-arrow">▼</span>
        </div>
        <button className="design-system-btn">
          <Settings size={16} />
          <span>Design System</span>
        </button>
      </div>

      {/* Top Right Controls */}
      <div className="control-group top-right">
        <button className="share-btn">
          <Upload size={16} />
          <span>Share</span>
        </button>
      </div>

      {/* Bottom Left Controls */}
      <div className="control-group bottom-left">
        <div className="zoom-controls">
          <button className="zoom-btn" onClick={handleZoomOut}>
            <Minus size={16} />
          </button>
          <span className="zoom-level">{zoom}%</span>
          <button className="zoom-btn" onClick={handleZoomIn}>
            <Plus size={16} />
          </button>
        </div>
                 <div className="color-picker-container" ref={colorPickerRef}>
           <button className="canvas-color-btn" onClick={toggleColorPicker} title="Canvas Settings">
             <Palette size={16} />
           </button>

                        {showColorPicker && (
               <div className="color-picker-panel">
                 <div className="color-gradient" onClick={handleGradientClick}>
                   <div className="gradient-overlay"></div>
                   <div className="color-selector" style={{ 
                     left: '20px', 
                     top: '20px',
                     borderColor: canvasColor === '#ffffff' ? '#000' : '#fff'
                   }}></div>
                 </div>

                 <div className="color-bar" onClick={handleHueClick}>
                   <div className="hue-slider"></div>
                 </div>

               <div className="hex-input-container">
                 <div className="color-preview" style={{ backgroundColor: canvasColor }}></div>
                 <input 
                   type="text" 
                   className="hex-input" 
                   value={canvasColor}
                   onChange={(e) => handleColorChange(e.target.value)}
                   placeholder="#2B2B2B"
                 />
               </div>

               <div className="dotted-texture-control">
                 <span>Dotted Texture</span>
                 <button 
                   className={`toggle-switch ${showDots ? 'active' : ''}`}
                   onClick={toggleDots}
                 >
                   <div className="toggle-slider"></div>
                 </button>
               </div>
             </div>
           )}
         </div>
      </div>

      {/* Bottom Right Controls */}
      <div className="control-group bottom-right">
        <button className="add-component-btn" title="Generate Component">
          <Plus size={20} />
        </button>
      </div>
    </div>
  );
};

export default Canvas;
